    <Box sx={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      p: 2
    }}>
      <Typography variant='h6'>{title}</Typography>
      <Button startIcon={<MoreHorizIcon />} />
    </Box>
  );
}

